import React from 'react';
import { motion } from 'framer-motion';
import './Projects.css';

const Projects = () => {
  const projects = [
    {
      title: "Multi-Tier Web Application",
      description: "Deployed scalable 3-tier architecture with auto-scaling, load balancing, and RDS Multi-AZ setup.",
      tags: ["EC2", "ALB", "RDS", "CloudFormation"]
    },
    {
      title: "Serverless Data Pipeline",
      description: "Built event-driven data processing pipeline using Lambda, S3, and DynamoDB with real-time analytics.",
      tags: ["Lambda", "S3", "DynamoDB", "Kinesis"]
    },
    {
      title: "CI/CD Pipeline",
      description: "Implemented automated deployment pipeline with testing, security scanning, and blue-green deployments.",
      tags: ["CodePipeline", "CodeBuild", "ECS", "Terraform"]
    }
  ];

  return (
    <section id="projects" className="projects-section">
      <div className="container">
        <motion.h2 
          className="section-title"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          Featured Projects
        </motion.h2>
        <div className="project-grid">
          {projects.map((project, index) => (
            <motion.div 
              key={index}
              className="project-card"
              initial={{ opacity: 0, y: 50 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.2, duration: 0.6 }}
              whileHover={{ y: -10 }}
              viewport={{ once: true }}
            >
              <div className="project-header">
                <h3>{project.title}</h3>
              </div>
              <div className="project-body">
                <p>{project.description}</p>
                <div className="tech-tags">
                  {project.tags.map((tag, i) => (
                    <motion.span 
                      key={i}
                      className="tech-tag"
                      whileHover={{ scale: 1.1 }}
                    >
                      {tag}
                    </motion.span>
                  ))}
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
